import{_ as a,a as t}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as l,o as r,c as i,a2 as n}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Kullanıcı Yükleme Sıklığı Sınırları","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/Safety/user-rate-limits.md","filePath":"tr-TR/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),d={name:"tr-TR/Safety/user-rate-limits.md"};function s(o,e,m,k,y,p){return r(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="kullanıcı-yukleme-sıklıgı-sınırları" tabindex="-1">Kullanıcı Yükleme Sıklığı Sınırları <a class="header-anchor" href="#kullanıcı-yukleme-sıklıgı-sınırları" aria-label="Permalink to &quot;Kullanıcı Yükleme Sıklığı Sınırları&quot;">​</a></h1><p>User rate limits, normal kullanıcıların veya ziyaretçilerin ana sayfadan ne kadar sık dosya yükleyebileceğini kontrol eder. Bu, herkese açık yükleme sayfalarının kötüye kullanılmasını önlemeye yardımcı olur.</p><p>Bu özellik yalnızca ana sayfa yüklemelerini etkiler. Yönetici yüklemeleri ve API Tokens ile yapılan yüklemeler user rate limits tarafından sınırlandırılmaz.</p><h2 id="nereden-yapılandırılır" tabindex="-1">Nereden Yapılandırılır? <a class="header-anchor" href="#nereden-yapılandırılır" aria-label="Permalink to &quot;Nereden Yapılandırılır?&quot;">​</a></h2><p>Yönetim panelini açın, ardından şuraya gidin:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+a+'" alt="User rate limit ayarları" loading="lazy"></p><h2 id="rate-limits-etkinlestirme" tabindex="-1">Rate Limits Etkinleştirme <a class="header-anchor" href="#rate-limits-etkinlestirme" aria-label="Permalink to &quot;Rate Limits Etkinleştirme&quot;">​</a></h2><p><code>Enable Rate Limits</code> açıldıktan sonra ImgBed son yüklemeleri yükleyenin IP adresine göre izler.</p><p>Varsayılan değerler:</p><table tabindex="0"><thead><tr><th>Ayar</th><th>Varsayılan</th><th>Açıklama</th></tr></thead><tbody><tr><td>Detection window</td><td>1.5 hours</td><td>Yükleme kayıtlarının ne kadar geriye dönük sayılacağı.</td></tr><tr><td>Max file count</td><td>20</td><td>Detection window içindeki en fazla dosya sayısı.</td></tr><tr><td>Single file size limit</td><td>20 MB</td><td>Tek dosyanın en fazla boyutu.</td></tr><tr><td>Total upload size limit</td><td>200 MB</td><td>Detection window içindeki toplam yükleme boyutu sınırı.</td></tr></tbody></table><p>Örneğin 1,5 saatlik pencere, 20 dosya, dosya başına 20 MB ve toplam 200 MB ayarlandığında aynı IP&#39;den yapılan yüklemeler herhangi bir limit aşılır aşılmaz engellenir.</p><h2 id="dosya-turlerini-haric-tutma" tabindex="-1">Dosya Türlerini Hariç Tutma <a class="header-anchor" href="#dosya-turlerini-haric-tutma" aria-label="Permalink to &quot;Dosya Türlerini Hariç Tutma&quot;">​</a></h2><p><code>Excluded upload file types</code>, normal kullanıcıların veya ziyaretçilerin seçili dosya kategorilerini yüklemesini engeller.</p><p>Kullanılabilir kategoriler:</p><table tabindex="0"><thead><tr><th>Tür</th><th>Açıklama</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif ve benzeri görsel dosyaları</td></tr><tr><td>Videos</td><td>mp4, webm, mov ve benzeri video dosyaları</td></tr><tr><td>Audio</td><td>mp3, flac, wav ve benzeri ses dosyaları</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx ve benzeri belge dosyaları</td></tr><tr><td>Other</td><td>Yukarıdaki kategorilerin dışındaki zip, rar, exe, apk gibi dosyalar</td></tr></tbody></table><p>Varsayılan olarak bir tür seçili değildir; bu da izin verildiği anlamına gelir.</p><p>Bir türe tıklamak onu vurgular; bu, o türün engellendiği anlamına gelir.</p><p><code>Other</code> seçilirse zip veya rar dosyası yükleyen ziyaretçiler engellenir ve bu dosya türünün desteklenmediği bildirilir.</p><h2 id="engelleme-mesajları" tabindex="-1">Engelleme Mesajları <a class="header-anchor" href="#engelleme-mesajları" aria-label="Permalink to &quot;Engelleme Mesajları&quot;">​</a></h2><p>Bir limit tetiklendiğinde kullanıcılar uygun mesajı görür:</p><p><img src="'+t+'" alt="Çok sık yükleme mesajı" loading="lazy"></p><table tabindex="0"><thead><tr><th>Senaryo</th><th>Mesajın anlamı</th></tr></thead><tbody><tr><td>Tek dosya çok büyük</td><td>Dosya çok büyük; yüklemeden önce sıkıştırılmalıdır.</td></tr><tr><td>Dosya türü engellendi</td><td>Bu dosya türü desteklenmiyor. Kaldırıp tekrar deneyin.</td></tr><tr><td>Yüklemeler çok sık</td><td>Son yüklemeler çok sık; yeniden deneme zamanı gösterilir.</td></tr><tr><td>Toplam boyut çok yüksek</td><td>Son toplam yükleme boyutu çok yüksek; yeniden deneme zamanı gösterilir.</td></tr></tbody></table><h2 id="ne-zaman-etkinlestirilmeli" tabindex="-1">Ne Zaman Etkinleştirilmeli? <a class="header-anchor" href="#ne-zaman-etkinlestirilmeli" aria-label="Permalink to &quot;Ne Zaman Etkinleştirilmeli?&quot;">​</a></h2><p>Yükleme ana sayfanız herkese açıksa user rate limits etkinleştirin.</p><p>Yaygın nedenler:</p><ul><li>Script ile toplu yükleme yapılmasından endişe ediyorsunuz.</li><li>Ziyaretçilerin büyük dosya yüklemelerini sınırlamak istiyorsunuz.</li><li>Normal kullanıcıların arşiv veya kurulum dosyası değil, yalnızca görsel yüklemesini istiyorsunuz.</li><li>Herkese açık yüklemeyi açık tutarken kaynak kullanımını kontrol etmek istiyorsunuz.</li></ul><p>Site yalnızca size aitse veya yalnızca yöneticiler yükleme yapabiliyorsa bu ayarı kapalı bırakabilirsiniz.</p>',28)])])}const b=l(d,[["render",s]]);export{h as __pageData,b as default};
